#include <stdio.h>
int main(){
    int N;
    if(scanf("%d",&N)!=1) return 0;
    long long a=0,b=1,c;
    if(N>=1) printf("%lld",a);
    if(N>=2) printf(" %lld",b);
    for(int i=2;i<N;++i){
        c=a+b;
        printf(" %lld",c);
        a=b;
        b=c;
    }
    printf("\n");
    return 0;
}

