import sys
def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    N=int(data[0])
    a,b=0,1
    terms=[]
    if N>=1:
        terms.append('0')
    if N>=2:
        terms.append('1')
    for _ in range(2,N):
        a,b=b,a+b
        terms.append(str(b))
    sys.stdout.write(' '.join(terms))
if __name__=="__main__":
    solve()

